1	import fs from "node:fs";
2	import path from "node:path";
3	import type { Scenario } from "./types.js";
4	
5	const SCENARIOS_DIR = path.join(process.cwd(), "data", "scenarios");
6	
7	function ensureDir() {
8	  if (!fs.existsSync(SCENARIOS_DIR)) {
9	    fs.mkdirSync(SCENARIOS_DIR, { recursive: true });
10	  }
11	}
12	
13	function canonicalFilePath(id: string) {
14	  return path.join(SCENARIOS_DIR, `${id}.json`);
15	}
16	
17	function filePath(id: string) {
18	  ensureDir();
19	
20	  const canonicalPath = canonicalFilePath(id);
21	  if (fs.existsSync(canonicalPath)) {
22	    return canonicalPath;
23	  }
24	
25	  for (const entry of fs.readdirSync(SCENARIOS_DIR)) {
26	    if (!entry.endsWith(".json")) {
27	      continue;
28	    }
29	
30	    const candidatePath = path.join(SCENARIOS_DIR, entry);
31	
32	    try {
33	      const scenario = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as Scenario;
34	      if (scenario.id === id) {
35	        return candidatePath;
36	      }
37	    } catch {
38	      continue;
39	    }
40	  }
41	
42	  return canonicalPath;
43	}
44	
45	export function listScenarios(): Scenario[] {
46	  ensureDir();
47	
48	  return fs
49	    .readdirSync(SCENARIOS_DIR)
50	    .filter((entry) => entry.endsWith(".json"))
51	    .map(
52	      (entry) => JSON.parse(fs.readFileSync(path.join(SCENARIOS_DIR, entry), "utf-8")) as Scenario
53	    );
54	}
55	
56	export function getScenario(id: string): Scenario | null {
57	  const target = filePath(id);
58	
59	  if (!fs.existsSync(target)) {
60	    return null;
61	  }
62	
63	  return JSON.parse(fs.readFileSync(target, "utf-8")) as Scenario;
64	}
65	
66	export function saveScenario(scenario: Scenario): void {
67	  ensureDir();
68	  fs.writeFileSync(filePath(scenario.id), JSON.stringify(scenario, null, 2), "utf-8");
69	}
70	
71	export function deleteScenario(id: string): boolean {
72	  const target = filePath(id);
73	
74	  if (!fs.existsSync(target)) {
75	    return false;
76	  }
77	
78	  fs.unlinkSync(target);
79	  return true;
80	}
